}
if (Q.scps_r >= Q.flp_r && Q.scps_r >= Q.lps_r && Q.scps_r >= Q.cps_r) {
    Q.largest_party = 'SCPS';
}

// coalitions
Q.lps_coalition = Q.flp_r + Q.lps_r;
Q.pps_coalition = Q.flp_r + Q.pps_r;
Q.scps_coalition = Q.flp_r + Q.scps_r;
Q.left_coalition = Q.flp_r + Q.cp_s_r;
Q.grand_coalition = Q.flp_r + Q.lps_r + Q.pps_r + Q.cps_r;
Q.bourgeois_coalition = Q.lps_r + Q.cps_r + Q.other_r;
Q.conservative_coalition = Q.cps_r + Q.scps_r;
Q.right_coalition = Q.cps_r + Q.other_r + Q.scps_r;
Q.cooperative_coalition = Q.cps_r + Q.pps_r + Q.other_r;
Q.scps_majority = Q.scps_r;
// this is an absurd concept lol
Q.united_front_coalition = Q.flp_r + Q.cp_s_r + Q.pps_r + Q.lps_r;
Q.anti_democratic_coalition = Q.cp_s_r;
// aka everyone except scps, cp_s, scps
Q.neo_lps_coalition = Q.flp_r + Q.lps_r + Q.pps_r + Q.cps_r + Q.other_r;

// calculate normalized class voting amounts (0 to 100)
for (var c of Q.classes) {
    var class_votes = 0;
    for (var party of Q.parties) {
        if (Q[c+'_'+party] < 0) {
            Q[c+'_'+party] = 0;
        }
        class_votes += Q[c+'_'+party];
    }
    for (var party of Q.parties) {
        Q[c + '_' + party + '_normalized'] = 100*Q[c+'_'+party]/class_votes;
        Q[c + '_' + party + '_display'] = Math.round(100*Q[c+'_'+party]/class_votes);
    }
}

// 1. calculate support for each of the parties
var urban_support = 0;
for (var party of Q.parties) {
    var party_support_urban = 0;
    for (var c of Q.classes) {
        if (c === "farmer" || c === "farmhand" || c === "res_worker") continue;   // skip farmer, farmhand, res_worker
        // but this version is somewhat more entertaining and allows for wilder swings in votes.
        // the other option basically necessitates a multi-class strategy. while the first option allows for a working-class-only strategy.
        if (Q.old_demographics) {
            // okay i'm pretty sure this is wrong, and the hard version is correct
            // basically this allows for "spillover" effects in other demographics.
            // so you can campaign among say the workers and
            party_support_urban += Q[c]*Q[c+'_'+party];
            // However, there should be a cap on how much party support you can get in a certain demo.
        } else  {
            party_support_urban += Q[c]*Q[c+'_'+party+'_normalized'];
        }
    }
    Q[party + '_support'] = party_support_urban;
    urban_support += party_support_urban;
}

var rural_support = 0;
for (var party of Q.parties) {
    var party_support_rural = 0;
    for (var c of ["farmer","farmhand","res_worker"]) {
        if (!Q.classes.includes(c)) continue;
        // but this version is somewhat more entertaining and allows for wilder swings in votes.
        // the other option basically necessitates a multi-class strategy. while the first option allows for a working-class-only strategy.
        if (Q.old_demographics) {
            // okay i'm pretty sure this is wrong, and the hard version is correct
            // basically this allows for "spillover" effects in other demographics.
            // so you can campaign among say the workers and
            party_support_rural += Q[c]*Q[c+'_'+party];
            // However, there should be a cap on how much party support you can get in a certain demo.
        } else  {
            party_support_rural += Q[c]*Q[c+'_'+party+'_normalized'];
        }
    }
    Q[party + '_support_rural'] = party_support_rural;
    rural_support += party_support_rural;
}

// 2. normalize support (fraction)
// 3. Round to integers
// TODO: round to 1 decimal instead of rounding to integers
// to do that, we multiply party_normalized*1000 and divide the rounded number by 10.

var total_support = urban_support + rural_support;

if (urban_support === 0) urban_support = 1;
if (rural_support === 0) rural_support = 1;



for (var party of Q.parties) {

    Q[party + '_urban_norm'] = Q[party + '_support'] / urban_support;
    Q[party + '_rural_norm'] = Q[party + '_support_rural'] / rural_support;

    Q[party + '_urban_votes'] = Math.round(Q[party + '_urban_norm'] * 100);
    Q[party + '_rural_votes'] = Math.round(Q[party + '_rural_norm'] * 100);
}


var urban_total = 0;

for (var party of Q.parties) {
    Q[party+'_urban_power'] = Math.pow(Q[party+'_urban_norm'],3);
    urban_total += Q[party+'_urban_power'];
}

var seat_sum = 0;
var remainders = [];

for (var party of Q.parties) {

    var exact = (Q[party+'_urban_power'] / urban_total) * Q.urban_seats;

    Q[party+'_urban_seats'] = Math.floor(exact);
    seat_sum += Q[party+'_urban_seats'];

    remainders.push({
        party: party,
        remainder: exact - Q[party+'_urban_seats']
    });
}

var seats_left = Q.urban_seats - seat_sum;

remainders.sort(function(a,b){
    return b.remainder - a.remainder;
});

for (var i = 0; i < seats_left; i++) {
    var p = remainders[i].party;
    Q[p+'_urban_seats'] += 1;
}


var rural_total = 0;

for (var party of Q.parties) {
    Q[party+'_rural_power'] = Math.pow(Q[party+'_rural_norm'],3);
    rural_total += Q[party+'_rural_power'];
}


var seat_sum = 0;
var remainders = [];

for (var party of Q.parties) {

    var exact = (Q[party+'_rural_power'] / rural_total) * Q.rural_seats;

    Q[party+'_rural_seats'] = Math.floor(exact);
    seat_sum += Q[party+'_rural_seats'];

    remainders.push({
        party: party,
        remainder: exact - Q[party+'_rural_seats']
    });
}

var seats_left = Q.rural_seats - seat_sum;

remainders.sort(function(a,b){
    return b.remainder - a.remainder;
});

for (var i = 0; i < seats_left; i++) {
    var p = remainders[i].party;
    Q[p+'_rural_seats'] += 1;
}


for (var party of Q.parties) {

    Q[party+'_seats'] =
        Q[party+'_urban_seats'] +
        Q[party+'_rural_seats'];
}

var total = 0;

for (var party of Q.parties) {
    total += Q[party+'_seats'];
}

console.log("TOTAL SEATS:", total);
console.log("EXPECTED:", Q.urban_seats + Q.rural_seats);

for (var party of Q.parties) {
    var combined_support = Q[party + '_support'] + Q[party + '_support_rural'];

    Q[party+'_normalized'] = combined_support / total_support;

    Q[party+'_votes_dec'] = Math.round(Q[party+'_normalized'] * 1000) / 10;

    if (Q.use_decimals) {
        Q[party+'_votes'] = Q[party+'_votes_dec'];
        Q[party + '_votes_disp'] = Q[party+'_votes_dec'].toFixed(1);
    }
    else {
        Q[party+'_votes'] = Math.round(Q[party+'_normalized'] * 100);

        Q[party + '_votes_disp'] = Q[party+'_votes_dec'].toFixed(1);
    }
}

console.log("FLP votes:", Q.flp_votes);
console.log("PPS votes:", Q.pps_votes);
console.log("CP(S) votes:", Q.cp_s_votes);

onDisplay.$code:
var mods_list = document.getElementById('mods_list');
// load mods from url
var mods_url = 'https://aucchen.github.io/social_democracy_mods/mod_list.tsv';
var table = document.createElement('table');
table.style.border = '1px solid';
table.style['border-collapse'] = 'collapse';
table.style['font-size'] = '0.8em';
Q.mods_table = {};
fetch(mods_url)
.then(response => response.text())
.then(text => {
    // split text
    var lines = text.split('\n');
    for (var i = 0; i < lines.length; i++) {
        var line_data = lines[i].split('\t');
        if (line_data.length < 5) {
            continue;
        }
        var tr = document.createElement('tr');
        for (var j = 0; j < 4; j++) {
            var td = document.createElement('td');
            if (i == 0) {
                td = document.createElement('th');
            }
            td.style.border = '1px solid';
            td.style.padding = '0.5em';
            td.textContent = line_data[j];

            tr.appendChild(td);
        }
        if (i > 0) {
            Q.mods_table[line_data[2]] = {
                name: line_data[0],
                author: line_data[1],
                description: line_data[3],
            };

        }
        table.appendChild(tr);
    }
    mods_list.appendChild(table);
})
.catch(err => console.log(err));

var submit = document.getElementById('submit');
submit.onclick = function() {
    var mod_url = document.getElementById('mod_url').value;
    // if it's a known mod, set the game's titlebar and author.
    if (Q.mods_table[mod_url]) {
        var mod_data = Q.mods_table[mod_url];
        var title = document.getElementById('game-title');
        title.textContent = mod_data.name;
        var author = document.getElementById('game-author');
        author.textContent = mod_data.author;
    }
    window.loadMod(mod_url);
};

