// allocate seats function
function allocateSeats(votes, totalSeats) {
    var seats = {};
    for (var p in votes) seats[p] = 0; // Set all party seats at 0

    for (var s = 0; s < totalSeats; s++) { //Loop once per seat to allocate
        var maxQ = -1;
        var winner = null; // 'winning' party of the seat
        for (var p in votes) {
            var q = votes[p] / (seats[p] + 1); // D'hondt quotient for each party
            if (q > maxQ) { // If this party has the highest quotient so far, they are the current winner of the seat
                maxQ = q; // Update maxQ to this party's quotient
                winner = p; // Winner of the seat is the party with the highest quotient
            }
        }
        seats[winner]++; //Increase winner seat count by 1
    }
    return seats; //return final seat distribution for all parties contesting
}

